/**
 * Admin reports — high-level platform metrics.
 * Aggregates from existing endpoints (slots, classrooms, students, leads).
 */

import { useEffect, useMemo, useState } from 'react'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import { fetchAllSlots, type SlotDto } from '../api/schedule'
import { fetchClassrooms, type ClassroomDto } from '../api/classrooms'
import { fetchAllStudents, type StudentWithSubscriptionDto } from '../api/subscriptions'
import { fetchStageCounts, STAGE_LABELS, type LeadStage } from '../api/crm'

function startOfMonth(d: Date): Date { const r = new Date(d); r.setDate(1); r.setHours(0,0,0,0); return r }
function startOfWeek(d: Date): Date { const r = new Date(d); const day = r.getDay(); r.setDate(r.getDate() + (day === 0 ? -6 : 1 - day)); r.setHours(0,0,0,0); return r }

interface MetricProps {
  label: string
  value: string | number
  hint?: string
  color?: string
}

function Metric({ label, value, hint, color = 'var(--violet, #6b5ce7)' }: MetricProps) {
  return (
    <div className="kb-card" style={{ padding: 20, display: 'flex', flexDirection: 'column', gap: 6 }}>
      <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: 'uppercase', color: 'var(--ink-soft)' }}>{label}</div>
      <div style={{ fontSize: 32, fontFamily: 'var(--f-display)', fontWeight: 900, color, lineHeight: 1 }}>{value}</div>
      {hint && <div style={{ fontSize: 12, color: 'var(--ink-soft)' }}>{hint}</div>}
    </div>
  )
}

export default function AdminReports() {
  const { toast, show } = useToast()
  const [slots, setSlots] = useState<SlotDto[]>([])
  const [classrooms, setClassrooms] = useState<ClassroomDto[]>([])
  const [students, setStudents] = useState<StudentWithSubscriptionDto[]>([])
  const [stageCounts, setStageCounts] = useState<Record<LeadStage, number> | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    setLoading(true)
    const monthStart = startOfMonth(new Date())
    const monthEnd = new Date(monthStart); monthEnd.setMonth(monthEnd.getMonth() + 1)

    Promise.allSettled([
      fetchAllSlots(monthStart.toISOString(), monthEnd.toISOString()),
      fetchClassrooms(),
      fetchAllStudents(),
      fetchStageCounts(),
    ])
      .then(([s, c, st, sc]) => {
        if (s.status === 'fulfilled') setSlots(s.value); else show('Слоты не загрузились', 'error')
        if (c.status === 'fulfilled') setClassrooms(c.value)
        if (st.status === 'fulfilled') setStudents(st.value)
        if (sc.status === 'fulfilled') setStageCounts(sc.value)
      })
      .finally(() => setLoading(false))
  }, [])

  const weekStart = useMemo(() => startOfWeek(new Date()), [])

  // ─── Метрики ──────────────────────────────────────────
  const metrics = useMemo(() => {
    const now = new Date()
    const weekSlots = slots.filter((s) => new Date(s.datetime) >= weekStart && new Date(s.datetime) < now)
    const conducted = slots.filter((s) => s.status === 'conducted').length
    const cancelled = slots.filter((s) => s.status === 'cancelled').length

    // Teacher load — hours per teacher this week
    const teacherLoad = new Map<string, number>()
    for (const s of weekSlots) {
      teacherLoad.set(s.teacherId, (teacherLoad.get(s.teacherId) ?? 0) + s.durationMin)
    }

    // Group fill rate
    const groupFillSum = classrooms.reduce((acc, c) => {
      const max = (c.metadata?.maxStudents as number | undefined) ?? 6
      return acc + Math.min(1, c.studentCount / max)
    }, 0)
    const groupFill = classrooms.length > 0 ? Math.round((groupFillSum / classrooms.length) * 100) : 0

    // Total students with active subscription
    const activeStudents = students.filter((s) => s.subscription && s.subscription.status === 'active').length

    // Running out (≤2 lessons left)
    const runningOut = students.filter((s) => s.subscription && (s.subscription.lessonsTotal - s.subscription.lessonsUsed) <= 2 && s.subscription.status === 'active').length

    // Conversion: (paid + active + churned) / all leads
    let conversionRate = 0
    if (stageCounts) {
      const total = Object.values(stageCounts).reduce((a, b) => a + b, 0)
      const converted = (stageCounts.paid ?? 0) + (stageCounts.active ?? 0) + (stageCounts.churned ?? 0)
      conversionRate = total > 0 ? Math.round((converted / total) * 100) : 0
    }

    // Churn rate
    let churnRate = 0
    if (stageCounts) {
      const total = (stageCounts.paid ?? 0) + (stageCounts.active ?? 0) + (stageCounts.paused ?? 0) + (stageCounts.churned ?? 0)
      churnRate = total > 0 ? Math.round(((stageCounts.churned ?? 0) / total) * 100) : 0
    }

    return { weekSlots, conducted, cancelled, teacherLoad, groupFill, activeStudents, runningOut, conversionRate, churnRate }
  }, [slots, classrooms, students, stageCounts, weekStart])

  return (
    <PlatformShell activeKey="admin">
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>📊</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>Отчёты</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>Платформа в цифрах</h1>
          </div>
        </div>
      </div>

      {loading ? (
        <div style={{ padding: 60, textAlign: 'center', color: 'var(--ink-soft)' }}>Загрузка отчётов…</div>
      ) : (
        <div style={{ maxWidth: 1200, margin: '0 auto', padding: '28px 16px', display: 'flex', flexDirection: 'column', gap: 28 }}>

          <section>
            <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 800 }}>Эта неделя</h2>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(180px,1fr))', gap: 16 }}>
              <Metric label="Слотов проведено" value={metrics.conducted} hint="за месяц" />
              <Metric label="Отменено" value={metrics.cancelled} hint="за месяц" color="#dc2626" />
              <Metric label="Загрузка преподов" value={metrics.teacherLoad.size} hint="активных на неделе" />
              <Metric label="Заполняемость групп" value={`${metrics.groupFill}%`} hint="средняя по платформе" color="#059669" />
            </div>
          </section>

          <section>
            <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 800 }}>Ученики</h2>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(180px,1fr))', gap: 16 }}>
              <Metric label="Всего" value={students.length} />
              <Metric label="С активной подпиской" value={metrics.activeStudents} color="#059669" />
              <Metric label="Заканчиваются уроки" value={metrics.runningOut} hint="≤2 осталось" color="#f59e0b" />
            </div>
          </section>

          <section>
            <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 800 }}>Воронка продаж</h2>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(180px,1fr))', gap: 16, marginBottom: 16 }}>
              <Metric label="Конверсия" value={`${metrics.conversionRate}%`} hint="лиды → оплата" />
              <Metric label="Churn" value={`${metrics.churnRate}%`} hint="отвалились / все клиенты" color="#dc2626" />
            </div>
            {stageCounts && (
              <div className="kb-card" style={{ padding: 20 }}>
                <h3 style={{ margin: '0 0 12px', fontSize: 14, fontWeight: 700 }}>Лиды по стадиям</h3>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                  {(Object.keys(STAGE_LABELS) as LeadStage[]).map((stage) => {
                    const count = stageCounts[stage] ?? 0
                    const max = Math.max(...Object.values(stageCounts), 1)
                    const pct = (count / max) * 100
                    return (
                      <div key={stage} style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                        <div style={{ minWidth: 160, fontSize: 13 }}>{STAGE_LABELS[stage]}</div>
                        <div style={{ flex: 1, background: 'var(--paper-2, #f9f8ff)', borderRadius: 4, height: 18, position: 'relative' }}>
                          <div style={{ position: 'absolute', left: 0, top: 0, height: '100%', width: `${pct}%`, background: 'var(--violet, #6b5ce7)', borderRadius: 4, transition: 'width .3s' }} />
                        </div>
                        <div style={{ minWidth: 36, fontSize: 14, fontWeight: 700, textAlign: 'right' }}>{count}</div>
                      </div>
                    )
                  })}
                </div>
              </div>
            )}
          </section>

          <section>
            <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 800 }}>Топ преподов по нагрузке (эта неделя)</h2>
            <div className="kb-card" style={{ padding: 20 }}>
              {metrics.teacherLoad.size === 0 ? (
                <div style={{ color: 'var(--ink-soft)', fontSize: 13 }}>Нет данных за неделю</div>
              ) : (
                <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
                  <thead>
                    <tr style={{ textAlign: 'left' }}>
                      <th style={{ padding: '6px 8px', fontWeight: 700, color: 'var(--ink-soft)' }}>Преподаватель</th>
                      <th style={{ padding: '6px 8px', fontWeight: 700, color: 'var(--ink-soft)' }}>Слотов</th>
                      <th style={{ padding: '6px 8px', fontWeight: 700, color: 'var(--ink-soft)' }}>Часов</th>
                    </tr>
                  </thead>
                  <tbody>
                    {Array.from(metrics.teacherLoad.entries())
                      .sort(([, a], [, b]) => b - a)
                      .slice(0, 10)
                      .map(([id, mins]) => {
                        const slotsCount = metrics.weekSlots.filter((s) => s.teacherId === id).length
                        return (
                          <tr key={id} style={{ borderTop: '1px solid var(--paper-3, #e5e2f0)' }}>
                            <td style={{ padding: '8px', fontFamily: 'monospace', fontSize: 12 }}>{id.slice(0, 12)}…</td>
                            <td style={{ padding: '8px' }}>{slotsCount}</td>
                            <td style={{ padding: '8px', fontWeight: 700 }}>{(mins / 60).toFixed(1)}ч</td>
                          </tr>
                        )
                      })}
                  </tbody>
                </table>
              )}
            </div>
          </section>
        </div>
      )}
    </PlatformShell>
  )
}
